// ============ X (Twitter) 公式埋め込みウィジェット ============
function XEmbedTimeline() {
  const containerRef = useRef(null);

  useEffect(() => {
    // widgets.jsを1度だけロード
    const SCRIPT_ID = "twitter-widgets-script";
    const renderTimeline = () => {
      // window.twttr.widgets.load() でDOM内の.twitter-timelineをレンダリング
      if (window.twttr && window.twttr.widgets && containerRef.current) {
        window.twttr.widgets.load(containerRef.current);
      }
    };

    if (document.getElementById(SCRIPT_ID)) {
      // すでにロード済みなら直接呼ぶ
      renderTimeline();
      return;
    }
    const s = document.createElement("script");
    s.id = SCRIPT_ID;
    s.src = "https://platform.twitter.com/widgets.js";
    s.async = true;
    s.charset = "utf-8";
    s.onload = renderTimeline;
    document.body.appendChild(s);
  }, []);

  return (
    <div ref={containerRef} style={{
      background: C.warmGray, minHeight: 380, padding: 12,
      maxHeight: 600, overflow: "hidden",
    }}>
      <a className="twitter-timeline"
        data-height="560"
        data-theme="light"
        data-chrome="noheader nofooter noborders transparent"
        data-tweet-limit="3"
        data-lang="ja"
        href="https://twitter.com/tuyosiusi?ref_src=twsrc%5Etfw">
        Tweets by @tuyosiusi
      </a>
    </div>
  );
}

